advanced.Content:
// JavaScript
import '@maersk-global/mds-components-core-pagination';
import '@maersk-global/mds-components-core-card';
import newsData from './news-data.json';

const renderNewsItems = (items) => {
  const newsContainer = document.getElementById('news-content');
  newsContainer.innerHTML = '';
  items.forEach((item) => {
    const card = document.createElement('mc-card');
    card.setAttribute('variant', 'bordless');
    card.setAttribute('heading', item.title);
    card.setAttribute('subheading', item.category);
    card.setAttribute('body', item.description);
    card.setAttribute('padding', '0');
    newsContainer.appendChild(card);
  });
};

const mcPagination = document.querySelector('mc-pagination');
mcPagination.totalrecords = newsData.length;
mcPagination.visiblepages = 7;
mcPagination.addEventListener('pagechange', (e) => {
  const currentPage = e.detail;
  const startIndex = (currentPage - 1) * 10;
  const endIndex = startIndex + 10;
  const currentItems = newsData.slice(startIndex, endIndex);
  renderNewsItems(currentItems);
});

// Render initial page
renderNewsItems(newsData.slice(0, 10));

// CSS
.news-container {
  display: flex;
  flex-direction: column;
  gap: 48px;
  max-width: 800px;
}

// HTML
<div class="news-container">
  <div id="news-content"></div>
  <mc-pagination></mc-pagination>
</div>

advanced.TableWithSelect:
// JavaScript
import '@maersk-global/mds-components-core-pagination';
import '@maersk-global/mds-components-community-table';

// Sample data - replace with your actual data
const allData = [
  { id: 1, name: 'Item 1', status: 'Active' },
  { id: 2, name: 'Item 2', status: 'Inactive' },
  // ... more data (100 items total)
];

const columns = [
  { key: 'id', label: 'ID' },
  { key: 'name', label: 'Name' },
  { key: 'status', label: 'Status' }
];

let currentPage = 1;
let pageSize = 10;
const dataSetSize = 100;

const pagination = document.querySelector('mc-pagination');
const table = document.querySelector('mc-table');

// Function to get paginated data
const getPaginatedData = () => {
  const startIndex = (currentPage - 1) * pageSize;
  const endIndex = startIndex + pageSize;
  return allData.slice(startIndex, endIndex);
};

const updateTable = () => {
  table.data = getPaginatedData();
};

// Set up initial state
table.columns = columns;
table.datakey = 'id';
updateTable();

pagination.totalrecords = dataSetSize;
pagination.pagesize = pageSize;
pagination.variant = 'select';
pagination.showpagesize = true;
pagination.showpagestatus = true;
pagination.labels = {
  pageSize: 'Rows per page:',
  pageStatus: '{{recordStart}} - {{recordEnd}} of {{totalRecords}} rows'
};

// Listen for page changes
pagination.addEventListener('pagechange', (e) => {
  currentPage = e.detail;
  updateTable();
});

// Listen for page size changes
pagination.addEventListener('pagesizechange', (e) => {
  pageSize = e.detail;
  currentPage = 1;
  pagination.currentpage = 1;
  updateTable();
});


// HTML
<mc-table id="advanced-table"></mc-table>
<mc-pagination id="advanced-pagination"></mc-pagination>

